const request = $('Review Detail API').first().json;
const runId = String(request.params?.run_id || request.query?.run_id || '').trim();
const rows = $input.all().map(item => item.json);
const row = rows.find(item => String(item.run_id || '').trim() === runId);

if (!runId) {
  return [{ json: { ok: false, error: 'Missing run_id.' } }];
}

if (!row) {
  return [{ json: { ok: false, error: 'Review item not found.' } }];
}

const parseJson = (value, fallback) => {
  try {
    return JSON.parse(value || fallback);
  } catch {
    return JSON.parse(fallback);
  }
};

const summaryLines = String(row.summary || '')
  .split('\n')
  .map(s => s.trim())
  .filter(Boolean);

return [{
  json: {
    ok: true,
    item: {
      run_id: row.run_id || '',
      submitted_at: row.submitted_at || '',
      department: row.department || '',
      meeting_title: row.meeting_title || '',
      meeting_type: row.meeting_type || '',
      language_hint: row.language_hint || '',
      source_mode: row.source_mode || '',
      status: row.status || '',
      reviewer_name: row.reviewer_name || '',
      reviewer_notes: row.reviewer_notes || '',
      summary: row.summary || '',
      summary_lines: summaryLines,
      action_items: parseJson(row.action_items_json, '[]'),
      key_decisions: parseJson(row.key_decisions_json, '[]'),
      risks_open_questions: parseJson(row.risks_open_questions_json, '[]'),
      employee_faq: parseJson(row.employee_faq_json, '[]'),
      ai_opportunities: parseJson(row.ai_opportunities_json, '[]'),
      ambassador_brief: parseJson(row.ambassador_brief_json, '{}'),
      final_markdown_draft: row.final_markdown_draft || '',
      final_markdown_edited: row.final_markdown_edited || '',
      final_markdown_approved: row.final_markdown_approved || '',
      notify_channel: row.notify_channel || 'none',
      error_message: row.error_message || '',
    }
  }
}];
